PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?president ?presidentLabel ?age
WHERE {
  ?president wdt:P39 wd:Q5708511 ;
              wdt:P509 ?cause ;
              wdt:P569 ?birth ;
              wdt:P570 ?death ;
              rdfs:label ?presidentLabel .
  VALUES ?cause { wd:Q10737 wd:Q3882219 } .
  FILTER(LANG(?presidentLabel) = "en") .
  BIND(xsd:integer(SUBSTR(STR(?birth), 1, 4)) AS ?birthYear) .
  BIND(xsd:integer(SUBSTR(STR(?death), 1, 4)) AS ?deathYear) .
  BIND(?deathYear - ?birthYear AS ?age) .
  FILTER(?birthYear > 0 && ?deathYear > 0)
}
ORDER BY ?president

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ql: <http://qlever.cs.uni-freiburg.de/builtin-functions/>

SELECT ?president ?presidentLabel ?age
WHERE {
  ?president wdt:P39 wd:Q5708511 ;
              wdt:P509 ?cause ;
              wdt:P569 ?birth ;
              wdt:P570 ?death ;
              rdfs:label ?presidentLabel .
  VALUES ?cause { wd:Q10737 wd:Q3882219 } .
  FILTER(LANG(?presidentLabel) = 'en')
  BIND(ql:year(?birth) AS ?birthYear)
  BIND(ql:year(?death) AS ?deathYear)
  BIND(?deathYear - ?birthYear AS ?age)
  FILTER(?age > 0)
}
LIMIT 10
